import{_ as n,o as e,c as s,a0 as o}from"./chunks/framework.Bogozrur.js";const u=JSON.parse('{"title":"레거시 소스 코드가 어떻게 AI 통제 정책이 되는가?","description":"스캐너가 레거시 애플리케이션 코드를 훑어서 AI 도구용 힌트를 도출해 내는 정적 구조 정보의 정책 연동 방식을 설명합니다.","frontmatter":{"title":"레거시 소스 코드가 어떻게 AI 통제 정책이 되는가?","description":"스캐너가 레거시 애플리케이션 코드를 훑어서 AI 도구용 힌트를 도출해 내는 정적 구조 정보의 정책 연동 방식을 설명합니다."},"headers":[],"relativePath":"posts/scanner-to-policy.md","filePath":"posts/scanner-to-policy.md"}'),t={name:"posts/scanner-to-policy.md"};function l(p,a,c,i,r,d){return e(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="레거시-소스-코드가-어떻게-ai-통제-정책이-되는가-scanner-to-policy" tabindex="-1">레거시 소스 코드가 어떻게 AI 통제 정책이 되는가? (Scanner to Policy) <a class="header-anchor" href="#레거시-소스-코드가-어떻게-ai-통제-정책이-되는가-scanner-to-policy" aria-label="Permalink to &quot;레거시 소스 코드가 어떻게 AI 통제 정책이 되는가? (Scanner to Policy)&quot;">​</a></h1><p>개발팀에 처음 AI 코딩 도구를 도입할 때 맞닥뜨리는 실질적인 딜레마가 있습니다.</p><blockquote><p>&quot;우리 회사의 레거시 프로젝트(예: 오래된 PHP 애플리케이션)는 보안 상태가 좋지 않아서 날것 그대로 AI 도구에 넘겨주기에는 너무 위험한데, 그렇다고 AI를 안 쓰기에는 생산성 손실이 아깝다.&quot;</p></blockquote><p>만약 하드코딩된 데이터베이스 접속 정보, 날것의 Raw SQL 질의문, 혹은 오래된 보안 취약점을 가진 클래스 파일들이 수두룩한 레거시 소스 코드가 그대로 AI 프롬프트 컨텍스트에 담겨 외부 LLM으로 유출되거나, AI가 이를 바탕으로 위험한 신규 코드를 제안한다면 곤란할 것입니다.</p><p>이 문제를 해결하기 위해 고안한 도구가 바로 <strong>GoVail Scanner</strong>입니다.</p><hr><h2 id="_1-scanner는-거창한-보안-진단-도구-sast-가-아닙니다" tabindex="-1">1. Scanner는 거창한 보안 진단 도구(SAST)가 아닙니다 <a class="header-anchor" href="#_1-scanner는-거창한-보안-진단-도구-sast-가-아닙니다" aria-label="Permalink to &quot;1. Scanner는 거창한 보안 진단 도구(SAST)가 아닙니다&quot;">​</a></h2><p>시중에는 이미 SonarQube, Veracode, Semgrep 같은 훌륭한 정적 보안 취약점 진단(SAST) 도구들이 많이 있습니다. GoVail Scanner가 그러한 전문적인 보안 진단 도구들과 경쟁하려는 것은 전혀 아닙니다.</p><p>Scanner의 목표는 훨씬 소박하고 구체적입니다.</p><blockquote><p>&quot;코드의 전반적인 구조와 위험 요소를 파악해, AI 에이전트가 이 코드베이스를 다룰 때 조심해야 할 &#39;가이드라인 힌트(Policy Hints)&#39;를 뽑아내는 것.&quot;</p></blockquote><p>이를 위해 GoVail Scanner는 다음과 같은 수준의 가벼운 탐지만을 수행합니다.</p><ul><li>프로젝트 프레임워크 힌트 감지 (Laravel 스타일인지, CodeIgniter 스타일인지, 혹은 프레임워크가 없는 날것의 PHP 파일인지)</li><li>명백하게 소스 코드 내에 하드코딩된 API Key나 패스워드 패턴 탐색</li><li>Raw SQL 패턴이 집중적으로 사용되는 위험한 파일 식별</li><li>공용 업로드 폴더와 같이 외부 접근 경로 노출 여부 확인</li></ul><hr><h2 id="_2-분석-결과에서-정책-policy-으로의-변환-흐름" tabindex="-1">2. 분석 결과에서 정책(Policy)으로의 변환 흐름 <a class="header-anchor" href="#_2-분석-결과에서-정책-policy-으로의-변환-흐름" aria-label="Permalink to &quot;2. 분석 결과에서 정책(Policy)으로의 변환 흐름&quot;">​</a></h2><p>Scanner가 소스 코드를 훑고 지나가면 두 가지 중요한 JSON 파일이 출력됩니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ 레거시 소스 코드 ]</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼ (GoVail Scanner 정적 스캔)</span></span>
<span class="line"><span>┌───────────────────────┐       ┌────────────────────────┐</span></span>
<span class="line"><span>│   scan-report.json    │       │   policy-hints.json    │</span></span>
<span class="line"><span>│  (상세 구조/위험 리포트)│       │  (게이트웨이용 룰 추천)  │</span></span>
<span class="line"><span>└───────────────────────┘       └───────────┬────────────┘</span></span>
<span class="line"><span>                                            │</span></span>
<span class="line"><span>                                            ▼ (정책 룰로 주입)</span></span>
<span class="line"><span>                                 [ GoVail Gateway ]</span></span></code></pre></div><ul><li><strong><code>scan-report.json</code></strong>: 개발자가 직접 보고 소스 코드를 개선하는 데 쓰는 참고용 상세 리포트입니다.</li><li><strong><code>policy-hints.json</code></strong>: GoVail Gateway가 읽고 실시간 필터링 정책으로 삼을 수 있는 기계 친화적인 설정값 조각(Hint)입니다. <ul><li>예: 스캔 결과 <code>db_connection.php</code> 파일에 하드코딩된 기밀(Secret)이 존재한다고 탐지되면, Gateway에 다음과 같은 가이드가 주입됩니다. <blockquote><p><em>&quot;이 프로젝트 컨텍스트를 사용하는 AI 프롬프트에 <code>db_connection.php</code>와 관련된 단어가 들어오거나, 그 내부 문자열로 추정되는 키가 노출되면 즉시 해당 요청을 차단할 것.&quot;</em></p></blockquote></li></ul></li></ul><hr><h2 id="_3-한계와-로드맵" tabindex="-1">3. 한계와 로드맵 <a class="header-anchor" href="#_3-한계와-로드맵" aria-label="Permalink to &quot;3. 한계와 로드맵&quot;">​</a></h2><p>현재의 스캐너는 완전한 자동화 연동 단계라기보다는, 정적 분석을 통해 설정 힌트를 제안하는 단계에 머물러 있습니다. 이 힌트 파일(<code>policy-hints.json</code>)을 Gateway가 동적으로 구독하여 실시간 룰 테이블에 머지하는 구조를 다듬어 나가는 것이 현재의 주요 개발 과제입니다.</p>`,20)])])}const _=n(t,[["render",l]]);export{u as __pageData,_ as default};
